"""
Product search tool.

This is NOT a ReAct tool loop - it's called deterministically by the SHORTLIST
specialist after query_writer generates a structured query.
"""

from dataclasses import dataclass
from typing import Optional

from src.catalog import CATALOG


@dataclass
class SearchQuery:
    """Structured search query generated by query_writer LLM."""
    category: Optional[str] = None
    keywords: list[str] = None
    price_min: Optional[float] = None
    price_max: Optional[float] = None
    color: Optional[str] = None
    size: Optional[str] = None
    top_k: int = 5
    sort: str = "relevance"  # "relevance", "price_asc", "price_desc"
    
    def __post_init__(self):
        if self.keywords is None:
            self.keywords = []


@dataclass
class ProductResult:
    """Simplified product info for display."""
    id: str
    title: str
    price: float
    currency: str
    brand: str
    color: str
    sizes: list[str]
    short_desc: str
    
    def to_display_dict(self) -> dict:
        """Convert to dict for display formatting."""
        return {
            "id": self.id,
            "title": self.title,
            "price": f"{self.price} {self.currency}",
            "brand": self.brand,
            "color": self.color,
            "sizes": ", ".join(self.sizes) if self.sizes else "N/A",
            "description": self.short_desc[:100] + "..." if len(self.short_desc) > 100 else self.short_desc
        }


def _calculate_relevance_score(product: dict, keywords: list[str]) -> int:
    """
    Simple relevance scoring based on keyword matches.
    
    Counts matches in title, tags, and description.
    This is a POC - production would use vector search or Elasticsearch.
    """
    if not keywords:
        return 1  # Default score if no keywords
    
    score = 0
    search_text = (
        product.get("title", "").lower() + " " +
        " ".join(product.get("tags", [])).lower() + " " +
        product.get("description", "").lower() + " " +
        product.get("category", "").lower()
    )
    
    for keyword in keywords:
        keyword_lower = keyword.lower()
        # Title matches are worth more
        if keyword_lower in product.get("title", "").lower():
            score += 3
        # Tag matches are valuable
        if any(keyword_lower in tag.lower() for tag in product.get("tags", [])):
            score += 2
        # Description/category matches
        if keyword_lower in search_text:
            score += 1
    
    return score


def product_search(query: SearchQuery) -> list[ProductResult]:
    """
    Search the product catalog with filters and relevance scoring.
    
    This function is called deterministically by the SHORTLIST specialist,
    NOT in a ReAct tool loop. The query is generated by query_writer LLM.
    
    Args:
        query: Structured search query with filters
        
    Returns:
        List of ProductResult objects sorted by relevance
    """
    results = []
    
    for product in CATALOG:
        # Filter: must be in stock
        if not product.get("in_stock", False):
            continue
        
        # Filter: category (if specified)
        if query.category:
            if product.get("category", "").lower() != query.category.lower():
                continue
        
        # Filter: price range
        price = product.get("price", 0)
        if query.price_min is not None and price < query.price_min:
            continue
        if query.price_max is not None and price > query.price_max:
            continue
        
        # Filter: color (if specified)
        if query.color:
            if product.get("color", "").lower() != query.color.lower():
                continue
        
        # Filter: size (if specified)
        if query.size:
            sizes = [s.lower() for s in product.get("size", [])]
            if query.size.lower() not in sizes:
                continue
        
        # Calculate relevance score
        score = _calculate_relevance_score(product, query.keywords)
        
        results.append((score, product))
    
    # Sort by relevance or price
    if query.sort == "price_asc":
        results.sort(key=lambda x: x[1].get("price", 0))
    elif query.sort == "price_desc":
        results.sort(key=lambda x: -x[1].get("price", 0))
    else:  # relevance
        results.sort(key=lambda x: -x[0])  # Higher score first
    
    # Take top_k results
    results = results[:query.top_k]
    
    # Convert to ProductResult objects
    return [
        ProductResult(
            id=p["id"],
            title=p["title"],
            price=p["price"],
            currency=p.get("currency", "PEN"),
            brand=p.get("brand", ""),
            color=p.get("color", ""),
            sizes=p.get("size", []),
            short_desc=p.get("description", "")
        )
        for _, p in results
    ]


def get_product_by_id(product_id: str) -> Optional[dict]:
    """Get a single product by ID."""
    for product in CATALOG:
        if product["id"] == product_id:
            return product
    return None


def get_products_by_ids(product_ids: list[str]) -> list[dict]:
    """Get multiple products by their IDs."""
    return [p for p in CATALOG if p["id"] in product_ids]
